template.script:
//

var SMI_MAP_POINTS = [];
try {
    var dataEl = document.getElementById('smi_map_data');
    if (dataEl && dataEl.dataset && dataEl.dataset.points) {
        SMI_MAP_POINTS = JSON.parse(dataEl.dataset.points);
    } else {
        SMI_MAP_POINTS = [];
    }
} catch (e) {
    SMI_MAP_POINTS = [];
}
window.SMI_MAP_POINTS = SMI_MAP_POINTS;

window.showPointPanel = function(pointId) {

    var pts = SMI_MAP_POINTS;
    var pt = null;

    for (var i = 0; i < pts.length; i++) {
        if (String(pts[i].id) === String(pointId)) {
            pt = pts[i];
            break;
        }
    }

    if (!pt) {
        return;
    }

    var body = document.getElementById('panel-body');
    var mats = pt.materials || [];

    var html = '';

    html += '<div style="margin-bottom:12px;">';
    html += '<div style="font-weight:600;font-size:15px;">' + pt.name + '</div>';
    html += '</div>';

    if (mats.length === 0) {

        html += '<div style="color:#94A3B8;font-size:13px;">Tidak ada bahan di titik ini.</div>';

    } else {

        html += '<table style="width:100%;border-collapse:collapse;font-size:13px;">';

        html += '<thead>';
        html += '<tr>';
        html += '<th style="text-align:left;padding:4px 0;border-bottom:1px solid #E2E8F0;">Bahan</th>';
        html += '<th style="text-align:right;padding:4px 0;border-bottom:1px solid #E2E8F0;">Stok</th>';
        html += '</tr>';
        html += '</thead>';

        html += '<tbody>';

        for (var j = 0; j < mats.length; j++) {

            var m = mats[j];

            var badge = m.is_low_stock
                ? '<span class="smi-badge smi-badge--low-stock">Sisa Sedikit</span>'
                : '<span class="smi-badge smi-badge--aman">Aman</span>';

            html += '<tr>' +
                '<td style="padding:10px 0;vertical-align:middle;">' +
                    '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">' +
                        '<span style="flex:1;min-width:0;display:block;word-break:break-word;">' + (m.name || '') + '</span>' +
                        badge +
                    '</div>' +
                '</td>' +

                '<td style="padding:10px 0;text-align:right;vertical-align:middle;">' +
                    (m.total_stok || 0).toFixed(1) + ' ' + (m.uom || '') +
                '</td>' +
            '</tr>';

            html += '<tr>' +
                '<td colspan="2" style="padding:6px 0 14px;">' +
                    '<a href="/smi/stok/' + m.id + '" ' +
                    'class="smi-btn smi-btn--secondary smi-btn--sm" ' +
                    'style="width:100%;justify-content:center;">' +
                    'Lihat Detail Stok' +
                    '</a>' +
                '</td>' +
            '</tr>';
        }

        html += '</tbody></table>';
    }

    // if user can manage points, add delete button
    try {
        var dataEl = document.getElementById('smi_map_data');
        var canManage = dataEl && dataEl.dataset && dataEl.dataset.canManage === '1';
        if (canManage) {
            html += '<div style="margin-top:12px;display:flex;gap:8px;justify-content:center;">';
            html += '<button class="smi-btn smi-btn--danger smi-btn--sm" onclick="window.showDeleteConfirm(' + pt.id + ')">Hapus Titik</button>';
            html += '</div>';
        }
    } catch (e) {}

    body.innerHTML = html;
}

window.showDeleteConfirm = function(pointId) {
    // lookup point details
    var pt = null;
    for (var i = 0; i < SMI_MAP_POINTS.length; i++) {
        if (String(SMI_MAP_POINTS[i].id) === String(pointId)) { pt = SMI_MAP_POINTS[i]; break; }
    }

    // if point has materials, show reminder modal instead of delete
    if (pt && pt.materials && pt.materials.length > 0) {
        var overlay2 = document.createElement('div');
        overlay2.className = 'smi-modal-overlay open';
        overlay2.style.zIndex = 9999;
        overlay2.addEventListener('click', function(ev){ if (ev.target === overlay2) document.body.removeChild(overlay2); });

        var modal2 = document.createElement('div');
        modal2.className = 'smi-modal';
        var listHtml = '<ul style="margin:8px 0;padding-left:18px;font-size:13px;">';
        for (var k = 0; k < pt.materials.length; k++) {
            var mm = pt.materials[k];
            listHtml += '<li>' + (mm.material_name || mm.name || '') + ' — ' + (mm.jumlah_tersisa || 0) + ' ' + (mm.satuan || '') + '</li>';
        }
        listHtml += '</ul>';

        modal2.innerHTML = '<div class="smi-modal__header"><span class="smi-modal__title">Titik masih memiliki stok</span></div>' +
            '<div class="smi-modal__body">' +
            '<div style="margin-bottom:8px;">Sebelum menghapus titik ini, pindahkan semua stok yang masih tersisa ke titik lain.</div>' +
            '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:12px;">' +
            '<button class="smi-btn smi-btn--secondary" id="smi_close_remind">Tutup</button>' +
            '</div></div>';

        overlay2.appendChild(modal2);
        document.body.appendChild(overlay2);

        document.getElementById('smi_close_remind').addEventListener('click', function(){ if (overlay2.parentNode) overlay2.parentNode.removeChild(overlay2); });
        return;
    }

    // create confirm modal for deletion
    var overlay = document.createElement('div');
    overlay.className = 'smi-modal-overlay open';
    overlay.style.zIndex = 9999;

    overlay.addEventListener('click', function(ev){
        if (ev.target === overlay) document.body.removeChild(overlay);
    });

    var modal = document.createElement('div');
    modal.className = 'smi-modal';
    modal.innerHTML = '<div class="smi-modal__header"><span class="smi-modal__title">Hapus Titik</span></div>' +
        '<div class="smi-modal__body"><div style="margin-bottom:12px;">Yakin ingin menghapus titik ini? Titik akan dihapus secara permanen.</div>' +
        '<div style="display:flex;gap:8px;justify-content:flex-end;">' +
        '<button class="smi-btn smi-btn--secondary" id="smi_cancel_delete">Batal</button>' +
        '<button class="smi-btn smi-btn--danger" id="smi_confirm_delete">Hapus</button>' +
        '</div></div>';

    overlay.appendChild(modal);
    document.body.appendChild(overlay);

    document.getElementById('smi_cancel_delete').addEventListener('click', function(){
        if (overlay.parentNode) overlay.parentNode.removeChild(overlay);
    });

    document.getElementById('smi_confirm_delete').addEventListener('click', function(){
        // call archive API
        fetch('/smi/api/inventory_points/' + pointId + '/archive', {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        }).then(function(resp){
            return resp.json().catch(function(){ return {} });
        }).then(function(data){
            // simple behavior: reload page on success
            if (data && data.success) {
                window.location.reload();
            } else {
                alert((data && data.error) || 'Gagal menghapus titik');
                if (overlay.parentNode) overlay.parentNode.removeChild(overlay);
            }
        }).catch(function(err){
            console.error(err);
            alert('Gagal menghapus titik');
            if (overlay.parentNode) overlay.parentNode.removeChild(overlay);
        });
    });
};
//
